export const handler = (input) => {
  const delta_bps = input.proposed_spread_bps - input.peer_median_spread_bps;
  const abs_delta = Math.abs(delta_bps);
  if (input.peer_count < 5) {
    return {
      within_band: true,
      delta_bps: delta_bps,
      requires_documentation: false,
      fair_lending_status: 'insufficient_peer_set_skip_check'
    };
  }
  if (abs_delta > 15) {
    return {
      within_band: false,
      delta_bps: delta_bps,
      requires_documentation: true,
      fair_lending_status: 'flag_audit_trail_required'
    };
  }
  return {
    within_band: true,
    delta_bps: delta_bps,
    requires_documentation: false,
    fair_lending_status: 'within_peer_band'
  };
};
